// ══════════════════════════════════════════════════════════
// Function Node 1: Filter & Normalize (v4)
// - Maps ESP32 'gsr' → 'gsr_adc'
// - Adds default device_id
// - Allows value=0 (sensor not ready yet)
// - Only rejects truly impossible non-zero values
// - Supports BOTH ESP32 naming (dht11_room_temp, dht11_humidity,
//   confidence, dht11_bias) AND simulator naming (room_temp,
//   humidity) for backward compatibility
// ══════════════════════════════════════════════════════════

var d = msg.payload;
if (!d || typeof d !== 'object') {
    return null;
}

// 1. Map ESP32 field names
if (d.gsr !== undefined && d.gsr_adc === undefined) {
    d.gsr_adc = d.gsr;
}

// 2. Default device_id
if (!d.device_id) {
    d.device_id = 'esp32_iot_health_01';
}

// 3. Default missing sensor values to 0
d.bpm       = (d.bpm !== undefined)       ? d.bpm       : 0;
d.spo2      = (d.spo2 !== undefined)      ? d.spo2      : 0;
d.body_temp = (d.body_temp !== undefined) ? d.body_temp : 0;
d.gsr_adc   = (d.gsr_adc !== undefined)   ? d.gsr_adc   : 0;

// 3b. DHT11: room temperature & humidity
//     ESP32 firmware sends: dht11_room_temp, dht11_humidity
//     Simulator may send:    room_temp, humidity
//     → Try ESP32 name first, fall back to no-prefix name
d.room_temp = (d['dht11_room_temp'] !== undefined) ? d['dht11_room_temp'] :
              (d.room_temp !== undefined)           ? d.room_temp           : 0;
d.humidity  = (d['dht11_humidity']  !== undefined) ? d['dht11_humidity']  :
              (d.humidity !== undefined)            ? d.humidity            : 0;

// 3c. ESP32 extra fields: confidence & dht11_bias
//     Default to 0 if not present (backward compat with old simulator data)
d.confidence  = (d.confidence  !== undefined) ? d.confidence  : 0;
d.dht11_bias = (d.dht11_bias !== undefined)  ? d.dht11_bias : 0;

// 3d. MAC address from ESP32 (new field)
var mac_address = (d.mac_address !== undefined) ? String(d.mac_address) : "";

// 4. Cast to float
var bpm       = parseFloat(d.bpm);
var spo2      = parseFloat(d.spo2);
var body_temp = parseFloat(d.body_temp);
var gsr_adc   = parseFloat(d.gsr_adc);
var room_temp = parseFloat(d.room_temp);
var humidity  = parseFloat(d.humidity);
var confidence  = parseFloat(d.confidence);
var dht11_bias = parseFloat(d.dht11_bias);

// 5. Outlier rejection: BPM, SpO2, body_temp, gsr_adc filters
if (bpm < 50 || bpm > 120) {
    node.warn('BPM out of valid range 50-120 (' + bpm + ') — dropping');
    return null;
}
// SpO2: chi chap nhan 80-100
if (spo2 !== 0 && (spo2 < 80 || spo2 > 100)) {
    node.warn('SpO2 out of range 80-100 (' + spo2 + ') — dropping');
    return null;
}
// Body temperature: chi chap nhan 30-50
if (body_temp !== 0 && (body_temp < 25 || body_temp > 50)) {
    node.warn('Temp out of range 30-50 (' + body_temp + ') — dropping');
    return null;
}
// GSR ADC: chi chap nhan 500-4000
if (gsr_adc !== 0 && (gsr_adc < 500 || gsr_adc > 4000)) {
    node.warn('GSR out of range 500-4000 (' + gsr_adc + ') — dropping');
    return null;
}
// 5b. DHT11 validation: room_temp -40..80, humidity 0..100
if (room_temp !== 0 && (room_temp < -40 || room_temp > 80)) {
    node.warn('room_temp out of range (' + room_temp + ') — dropping');
    return null;
}
if (humidity !== 0 && (humidity < 0 || humidity > 100)) {
    node.warn('humidity out of range (' + humidity + ') — dropping');
    return null;
}

// 6. Save raw backup for Data Lake (preserves ALL original ESP32 fields)
msg.raw_backup = {
    device_id:      String(d.device_id),
    mac_address:    mac_address,
    timestamp:      d.timestamp || Date.now(),
    mode:           d.mode,
    bpm:            bpm,
    spo2:           spo2,
    body_temp:      body_temp,
    gsr_adc:        gsr_adc,
    dht11_room_temp: room_temp,   // always stored as dht11_room_temp
    dht11_humidity:  humidity,    // always stored as dht11_humidity
    confidence:       confidence,
    dht11_bias:      dht11_bias,
    ingested_at:     new Date()
};

// 7. Clean payload for next node
msg.payload = {
    device_id:   String(d.device_id),
    mac_address: mac_address,
    timestamp:   d.timestamp || Date.now(),
    bpm:         bpm,
    spo2:        spo2,
    body_temp:   body_temp,
    gsr_adc:     gsr_adc,
    room_temp:   room_temp,
    humidity:    humidity,
    confidence:  confidence,
    dht11_bias:  dht11_bias,
    mode:        d.mode
};

return msg;

// ══════════════════════════════════════════════════════════
// Function Node 2: Feature Engineering
// Computes 8 derived features to match train_model.py exactly.
// Uses epsilon = 1e-6 to prevent division by zero.
// ══════════════════════════════════════════════════════════

var d   = msg.payload;
var eps = 1e-6;

var bpm       = d.bpm;
var spo2      = d.spo2;
var body_temp = d.body_temp;
var gsr_adc   = d.gsr_adc;
var room_temp = d.room_temp;
var humidity  = d.humidity;

// ── 8 Engineered Features (mirroring train_model.py) ────

// 1. bpm_spo2_ratio = bpm / (spo2 + eps)
d.bpm_spo2_ratio = bpm / (spo2 + eps);

// 2. temp_gsr_interaction = body_temp * gsr_adc / 1000
d.temp_gsr_interaction = body_temp * gsr_adc / 1000;

// 3. bpm_temp_product = bpm * body_temp
d.bpm_temp_product = bpm * body_temp;

// 4. spo2_gsr_ratio = spo2 / (gsr_adc + eps)
d.spo2_gsr_ratio = spo2 / (gsr_adc + eps);

// 5. bpm_deviation = abs(bpm - 75)
d.bpm_deviation = Math.abs(bpm - 75);

// 6. temp_deviation = abs(body_temp - 36.8)
d.temp_deviation = Math.abs(body_temp - 36.8);

// 7. gsr_deviation = abs(gsr_adc - 2200)
d.gsr_deviation = Math.abs(gsr_adc - 2200);

// 8. physiological_stress_index = (bpm - 75)/75 + (gsr_adc - 2200)/2200
d.physiological_stress_index = (bpm - 75) / 75 + (gsr_adc - 2200) / 2200;

// 9. heat_index = body_temp + 0.05 * humidity (DHT11)
d.heat_index = body_temp + 0.05 * humidity;

// 10. comfort_index = based on room_temp + humidity (DHT11)
//    0=uncomfortable, 1=comfortable, -1=cold/heat stress
var ideal_room_temp = 25; // comfortable room temp C
var ideal_humidity  = 60; // comfortable humidity %
d.comfort_index = 1.0 - Math.abs(room_temp - ideal_room_temp) / 20
                         - Math.abs(humidity  - ideal_humidity) / 100;
d.comfort_index = Math.max(-1, Math.min(1, d.comfort_index));

msg.payload = d;
return msg;

// Save the full engineered payload before HTTP request overwrites msg.payload
msg.sensorPayload = JSON.parse(JSON.stringify(msg.payload));
return msg;

// ══════════════════════════════════════════════════════════
// Function Node 3: Attach Label & Build Data Lake (v5)
//
// Luong xu ly:
//   - final_result (realtime_health_data): chi luu sensor + prediction
//   - datalake_raw: day du raw + features + metadata (vien vien)
//
// final_result chi chua:
//   device_id, mac_address, timestamp, ingested_at,
//   bpm, spo2, body_temp, gsr_adc,
//   room_temp, humidity,
//   label, confidence
//
// datalake_raw chua day du tat ca:
//   source, device_id, mac_address, timestamp, mode,
//   raw_payload, sensor, features, prediction,
//   data_quality, schema_version, ingested_at, processing_latency_ms
//
// ══════════════════════════════════════════════════════════

var sensor = msg.sensorPayload || {};
var httpResp = msg.payload;
var statusCode = msg.statusCode;
var rawPayload = msg.raw_backup || {};

// ── Output 1: final_result / realtime_health_data ────────────
// Chi luu cac truong thuc su can thiet. KHONG luu engineered features.
var finalResult = {
    device_id:   String(rawPayload.device_id || sensor.device_id || "unknown"),
    mac_address: String(rawPayload.mac_address || ""),
    timestamp:   rawPayload.timestamp || Date.now(),
    ingested_at: new Date(),

    // 4 sensor chinh
    bpm:        sensor.bpm,
    spo2:       sensor.spo2,
    body_temp:  sensor.body_temp,
    gsr_adc:   sensor.gsr_adc,

    // 2 DHT11 fields
    room_temp:  sensor.room_temp,
    humidity:   sensor.humidity,

    // Prediction
    label:      null,
    confidence: null
};

if (statusCode === 200 && httpResp && httpResp.predicted_label) {
    finalResult.label = httpResp.predicted_label;
    finalResult.confidence = httpResp.confidence;
} else {
    finalResult.label = "PENDING/ERROR";
    node.warn("Prediction failed or Backend Offline. Check FastAPI at port 8000.");
}

var msg1 = { payload: finalResult };

// ── Build Data Lake document (rich metadata) ─────────────────
var latencyMs = (rawPayload.timestamp)
    ? (Date.now() - parseInt(rawPayload.timestamp))
    : null;

var datalakeDoc = {
    // ── Source identification ────────────────────────────────
    source:         "mqtt_esp32",
    source_topic:   "ptit/health/data",

    // ── Device & timing ─────────────────────────────────────
    device_id:      String(rawPayload.device_id || sensor.device_id || "unknown"),
    mac_address:   String(rawPayload.mac_address || ""),
    timestamp:      rawPayload.timestamp || Date.now(),
    mode:           rawPayload.mode !== undefined ? rawPayload.mode : null,

    // ── Raw MQTT payload (original, untouched) ──────────────
    raw_payload:    JSON.parse(JSON.stringify(rawPayload)),

    // ── Normalized sensor values ────────────────────────────
    sensor: {
        bpm:       rawPayload.bpm,
        spo2:      rawPayload.spo2,
        body_temp: rawPayload.body_temp,
        gsr_adc:   rawPayload.gsr_adc,
        dht11_room_temp: rawPayload.dht11_room_temp,
        dht11_humidity:  rawPayload.dht11_humidity,
        confidence:      rawPayload.confidence,
        dht11_bias:      rawPayload.dht11_bias,
        mac_address:     String(rawPayload.mac_address || "")
    },

    // ── Engineered features (ML training features) ─────────
    features: {
        bpm_spo2_ratio:             sensor.bpm_spo2_ratio,
        temp_gsr_interaction:       sensor.temp_gsr_interaction,
        bpm_temp_product:           sensor.bpm_temp_product,
        spo2_gsr_ratio:             sensor.spo2_gsr_ratio,
        bpm_deviation:              sensor.bpm_deviation,
        temp_deviation:             sensor.temp_deviation,
        gsr_deviation:              sensor.gsr_deviation,
        physiological_stress_index: sensor.physiological_stress_index,
        heat_index:               sensor.heat_index,
        comfort_index:             sensor.comfort_index
    },

    // ── Prediction result ────────────────────────────────────
    prediction: (statusCode === 200 && httpResp && httpResp.predicted_label)
        ? {
            label:      httpResp.predicted_label,
            confidence: httpResp.confidence
        }
        : null,

    // ── Pipeline metadata ───────────────────────────────────
    data_quality:    rawPayload.bpm !== 0 && rawPayload.spo2 !== 0 && rawPayload.body_temp !== 0
                        ? "normalized" : "raw",
    schema_version:  "1.3",
    ingested_at:      new Date(),
    processing_latency_ms: latencyMs
};

// ── Output 2: datalake_raw (Data Lake) ────────────────
var msg2 = { payload: datalakeDoc };

return [msg1, msg2];
